#!/usr/bin/env bash
# drive-a-deal-to-close-with-a-mut.sh — Drive a deal to close with a Mutual Action Plan（用双向行动计划驱动成交） SOP walkthrough for B2B 大客户销售.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="B2B 大客户销售"
WORKFLOW="Drive a deal to close with a Mutual Action Plan（用双向行动计划驱动成交）"

usage() {
  cat <<EOF
drive-a-deal-to-close-with-a-mut.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./drive-a-deal-to-close-with-a-mut.sh             # interactive
  ./drive-a-deal-to-close-with-a-mut.sh --dry-run
  ./drive-a-deal-to-close-with-a-mut.sh --json
  ./drive-a-deal-to-close-with-a-mut.sh --explain
  ./drive-a-deal-to-close-with-a-mut.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "Drive a deal to close with a Mutual Action Plan（用双向行动计划驱动成交）" 工作流。

一句话: After a verbal-yes, *co-build* a dated close plan that walks both sides through legal, security, procurement, and go-live — because **deals die in the paper process**, not at "yes." The late-stage de-stall motion. (evidence: [T03-S017, T03-S005])

入门 SOP 共 5 步, 失败模式自检 4 项。

相关心智模型:
  • 问 ⇄ 教 ⇄ 筛:三派第一性张力,资深人按层混用: 复杂销售的方法论分三派——诊断式提问(SPIN/Gap:「客户有答案,问到痛点不可否认为止」)⇄ 挑战式教学(Challenger:「客户对自己问题的认知是错的,用商业洞见 reframe」)⇄ 资格
  • 头号对手是「不决策」,不是竞品: 预测内丢单的最大去向不是输给对手,而是客户「什么都不做」——维持现状;且一旦购买意向形成,买方更怕「搞砸」(FOMU)而非「错过」(FOMO),所以晚期停滞要按「犹豫」处理(去风险),不是按「异议」处

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**Co-build the MAP with the buyer** — list every step from now to go-live (legal/MSA, security review, procurement, exec sign-off, implementation) with owners and dates, *together*. (evidence: [T03-S017])"
  "**Map the Paper Process** — identify the procurement/legal/security path (MSA, redlines, SOC 2, DPA) explicitly. (evidence: [T03-S005])"
  "**Pre-empt security/procurement gates** — surface SOC 2/DPA/vendor questionnaires *early* (these are table stakes / auto-disqualifiers in enterprise procurement). (evidence: [T03-S005])"
  "**Keep the MAP live + track engagement** — review it on every call; in a digital sales room, watch which stakeholder went dark. (evidence: [T03-S017])"
  "**Defeat indecision (JOLT)** — when a qualified deal stalls late, treat it as *indecision* (FOMU), not lost-to-competitor: judge the indecision, offer a recommendation, limit options, take risk off the table. (evidence: [T03-S032, T03-S033])"
)
declare -a FAILURE_MODES=(
  "**Building the MAP alone and handing it over**: buyers read it as the seller's agenda and disengage. Avoid: co-author it live with the buyer; keep it in a shared room. (evidence: [T03-S017])"
  "**\"We got a verbal yes, the deal's done\"**: deals die in the paper process (redlines/security/procurement). Avoid: map and pre-empt the procurement/security/legal path early. (evidence: [T03-S005])"
  "**Discovering a security review / missing SOC 2 at the finish line**: a late security gate slips or kills the close. Avoid: surface SOC 2/DPA/questionnaires at the business-case stage. (evidence: [T03-S005])"
  "**Treating a late-stage stall as a lost deal or a slow buyer**: it's usually indecision (FOMU). Avoid: JOLT it — recommend, limit options, de-risk; don't passively \"circle back.\" (evidence: [T03-S033, T03-S032])"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "drive-a-deal-to-close-with-a-mut-walkthrough"
fi
